#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>

/* == EXEMPLE =======================================
 * Pipeline deux pipes : ajouter 10
 * Meme pattern : pipe1 -> lire -> transformer -> pipe2.
 * Ici on ajoute 10 au lieu de multiplier par 2.
 * ================================================= */
void example_pipeline_add(void) {
    int p1[2], p2[2];
    pipe(p1);
    pipe(p2);
    write(p1[1], "5", 1);
    close(p1[1]);
    char b1[8];
    ssize_t n1 = read(p1[0], b1, sizeof(b1) - 1);
    b1[n1] = '\0';
    close(p1[0]);
    int v = atoi(b1) + 10;
    char b2[8];
    snprintf(b2, sizeof(b2), "%d", v);
    write(p2[1], b2, strlen(b2));
    close(p2[1]);
    char out[8];
    ssize_t n2 = read(p2[0], out, sizeof(out) - 1);
    out[n2] = '\0';
    close(p2[0]);
    printf("In: 5, Out: %s\n", out);
}
